const strategies = $input.first().json;
if (!strategies || strategies.length === 0) {
  return [{ json: { skip: true, reason: 'No active strategies. Run Content Research workflow first.' } }];
}
const dayIndex = new Date().getDay();
const strategy = strategies[dayIndex % strategies.length];
return [{ json: { ...strategy, skip: false } }];

const s = $input.first().json;
const today = new Date().toLocaleDateString('en-US', {weekday:'long', year:'numeric', month:'long', day:'numeric'});
const prompt = `You are EZRA, an autonomous content creator. Generate one high-quality piece of content.

STRATEGY:
Niche: ${s.niche}
Platform: ${s.platform}
Format: ${s.content_format}
Target Audience: ${s.target_audience}
Monetization: ${s.monetization}
Cadence: ${s.posting_cadence}

Today: ${today}

Return ONLY a valid JSON object (no markdown, no explanation):
{
  "title": "compelling title optimized for the platform",
  "hook": "first line that stops the scroll",
  "body": "full content body formatted for the platform",
  "cta": "call to action leading toward monetization",
  "tags": "relevant hashtags or keywords comma separated"
}

Guidelines:
- Be genuinely useful and specific, not generic
- The hook must stop scrolling immediately
- Format for the platform: short paragraphs for social, headers for blogs
- Write as a knowledgeable human expert, not as an AI
- Choose a timely, relevant topic within the niche today`;

return [{ json: {
  strategy: s,
  request: {
    model: 'claude-sonnet-4-6',
    max_tokens: 3000,
    messages: [{ role: 'user', content: prompt }]
  }
}}];

const response = $input.first().json;
const text = response.content[0].text.trim();
const cleaned = text.replace(/^```json\n?/, '').replace(/^```\n?/, '').replace(/\n?```$/, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  throw new Error('Claude did not return valid JSON: ' + text.substring(0, 300));
}
const strategy = $('Build Content Prompt').first().json.strategy;
return [{ json: {
  strategy_id: strategy.id,
  niche: strategy.niche,
  platform: strategy.platform,
  content_format: strategy.content_format,
  title: parsed.title,
  body: parsed.body,
  hook: parsed.hook,
  cta: parsed.cta,
  tags: parsed.tags
}}];
